     5→//! Query operations for Gallops JSON
     6→//!
     7→//! Implements read operations: muster, saddle, parade, retire.
     8→//! All operations read from Gallops JSON and optionally paddock files.
     9→
    10→use crate::jjrf_favor::jjrf_Firemark as Firemark;
    11→use crate::jjrf_favor::jjrf_Coronet as Coronet;
    12→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
    13→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
    14→use crate::jjrs_steeplechase::{jjrs_SteeplechaseEntry, jjrs_get_entries, jjrs_ReinArgs};
    15→use serde::Serialize;
    16→use std::fs;
