    18→/// Resolve the default heat (first racing heat) when no target is specified
    19→pub fn jjrq_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
    20→    for (heat_key, heat) in &gallops.heats {
    21→        if heat.status == HeatStatus::Racing {
    22→            return Ok(heat_key.clone());
    23→        }
    24→    }
    25→    Err("No racing heats found".to_string())
    26→}
    27→
    28→// ============================================================================
    29→// Muster - List all Heats with summary information
    30→// ============================================================================
    31→
    32→/// Arguments for muster command
    33→#[derive(Debug)]
    34→pub struct jjrq_MusterArgs {
    35→    pub file: std::path::PathBuf,
    36→    pub status: Option<String>,
    37→}
    38→
    39→/// Run the muster command - list Heats as TSV
    40→pub fn jjrq_run_muster(args: jjrq_MusterArgs) -> i32 {
    41→    let gallops = match Gallops::jjrg_load(&args.file) {
    42→        Ok(g) => g,
    43→        Err(e) => {
    44→            eprintln!("jjx_muster: error: {}", e);
    45→            return 1;
    46→        }
    47→    };
    48→
    49→    // Collect heats with status info for sorting
    50→    let mut heats_by_status: Vec<(&String, &crate::jjrg_gallops::jjrg_Heat)> = gallops.heats.iter().collect();
    51→
    52→    // Apply status filter if specified
    53→    if let Some(ref filter_status) = args.status {
    54→        let filter_lowercase = filter_status.to_lowercase();
    55→        heats_by_status.retain(|(_, heat)| {
    56→            let heat_status_str = match heat.status {
    57→                HeatStatus::Racing => "racing",
    58→                HeatStatus::Stabled => "stabled",
    59→                HeatStatus::Retired => "retired",
    60→            };
    61→            heat_status_str == filter_lowercase
    62→        });
    63→    }
    64→
    65→    // Sort: racing first, then stabled, then retired
    66→    heats_by_status.sort_by(|a, b| {
    67→        let a_status_order = match a.1.status {
    68→            HeatStatus::Racing => 0,
    69→            HeatStatus::Stabled => 1,
    70→            HeatStatus::Retired => 2,
    71→        };
    72→        let b_status_order = match b.1.status {
    73→            HeatStatus::Racing => 0,
    74→            HeatStatus::Stabled => 1,
    75→            HeatStatus::Retired => 2,
    76→        };
    77→        a_status_order.cmp(&b_status_order)
    78→    });
    79→
    80→    // Set up table with column definitions
    81→    let mut table = jjrp_Table::jjrp_new(vec![
    82→        jjrp_Column::new("₣Fire", jjrp_Align::Left),
    83→        jjrp_Column::new("Silks", jjrp_Align::Left),
    84→        jjrp_Column::new("Status", jjrp_Align::Left),
    85→        jjrp_Column::new("Done", jjrp_Align::Right),
    86→        jjrp_Column::new("Total", jjrp_Align::Right),
    87→    ]);
    88→
    89→    // Measure all rows to compute column widths
    90→    for (key, heat) in &heats_by_status {
    91→        // Count paces where state != Abandoned
    92→        let defined_count = heat.paces.values().filter(|pace| {
    93→            if let Some(tack) = pace.tacks.first() {
    94→                tack.state != PaceState::Abandoned
    95→            } else {
    96→                true
    97→            }
    98→        }).count();
    99→
   100→        // Count paces where state == Complete
   101→        let completed_count = heat.paces.values().filter(|pace| {
   102→            if let Some(tack) = pace.tacks.first() {
   103→                tack.state == PaceState::Complete
   104→            } else {
   105→                false
   106→            }
   107→        }).count();
   108→
   109→        let status_str = match heat.status {
   110→            HeatStatus::Racing => "racing",
   111→            HeatStatus::Stabled => "stabled",
   112→            HeatStatus::Retired => "retired",
   113→        };
   114→
   115→        table.jjrp_measure(&[
   116→            key,
   117→            &heat.silks,
   118→            status_str,
   119→            &completed_count.to_string(),
   120→            &defined_count.to_string(),
   121→        ]);
   122→    }
   123→
   124→    // Print header and separator
   125→    table.jjrp_print_header();
   126→    table.jjrp_print_separator();
   127→
   128→    // Print data rows
   129→    for (key, heat) in heats_by_status {
   130→        // Count paces where state != Abandoned
   131→        let defined_count = heat.paces.values().filter(|pace| {
   132→            if let Some(tack) = pace.tacks.first() {
   133→                tack.state != PaceState::Abandoned
   134→            } else {
   135→                true
   136→            }
   137→        }).count();
   138→
   139→        // Count paces where state == Complete
   140→        let completed_count = heat.paces.values().filter(|pace| {
   141→            if let Some(tack) = pace.tacks.first() {
   142→                tack.state == PaceState::Complete
   143→            } else {
   144→                false
   145→            }
   146→        }).count();
   147→
   148→        let status_str = match heat.status {
   149→            HeatStatus::Racing => "racing",
   150→            HeatStatus::Stabled => "stabled",
   151→            HeatStatus::Retired => "retired",
   152→        };
   153→
   154→        table.jjrp_print_row(&[
   155→            key,
   156→            &heat.silks,
   157→            status_str,
   158→            &completed_count.to_string(),
   159→            &defined_count.to_string(),
   160→        ]);
   161→    }
   162→
   163→    0
   164→}
