   166→// ============================================================================
   167→// Saddle - Return context needed to saddle up on a Heat
   168→// ============================================================================
   169→
   170→/// Arguments for saddle command
   171→#[derive(Debug)]
   172→pub struct jjrq_SaddleArgs {
   173→    pub file: std::path::PathBuf,
   174→    pub firemark: Firemark,
   175→}
   176→
   177→/// Output structure for saddle command
   178→#[derive(Serialize)]
   179→pub(crate) struct zjjrq_SaddleOutput {
   180→    pub(crate) heat_silks: String,
   181→    pub(crate) paddock_file: String,
   182→    pub(crate) paddock_content: String,
   183→    #[serde(skip_serializing_if = "Option::is_none")]
   184→    pub(crate) pace_coronet: Option<String>,
   185→    #[serde(skip_serializing_if = "Option::is_none")]
   186→    pub(crate) pace_silks: Option<String>,
   187→    #[serde(skip_serializing_if = "Option::is_none")]
   188→    pub(crate) pace_state: Option<String>,
   189→    #[serde(skip_serializing_if = "Option::is_none")]
   190→    pub(crate) spec: Option<String>,
   191→    #[serde(skip_serializing_if = "Option::is_none")]
   192→    pub(crate) direction: Option<String>,
   193→    pub(crate) recent_work: Vec<jjrs_SteeplechaseEntry>,
   194→}
   195→
   196→/// Run the saddle command - return Heat context
   197→pub fn jjrq_run_saddle(args: jjrq_SaddleArgs) -> i32 {
   198→    let gallops = match Gallops::jjrg_load(&args.file) {
   199→        Ok(g) => g,
   200→        Err(e) => {
   201→            eprintln!("jjx_saddle: error: {}", e);
   202→            return 1;
   203→        }
   204→    };
   205→
   206→    let heat_key = args.firemark.jjrf_display();
   207→    let heat = match gallops.heats.get(&heat_key) {
   208→        Some(h) => h,
   209→        None => {
   210→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
   211→            return 1;
   212→        }
   213→    };
   214→
   215→    // Check if heat is stabled (cannot saddle stabled heat)
   216→    if heat.status == HeatStatus::Stabled {
   217→        eprintln!("jjx_saddle: error: Cannot saddle stabled heat '{}'", heat_key);
   218→        return 1;
   219→    }
   220→
   221→    // Read paddock file content
   222→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   223→        Ok(content) => content,
   224→        Err(e) => {
   225→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   226→            return 1;
   227→        }
   228→    };
   229→
   230→    // Get recent steeplechase entries
   231→    let recent_work = jjrs_get_entries(&jjrs_ReinArgs {
   232→        firemark: args.firemark.jjrf_as_str().to_string(),
   233→        limit: 10,
   234→    }).unwrap_or_default();
   235→
   236→    // Find first actionable pace (rough or bridled)
   237→    let mut output = zjjrq_SaddleOutput {
   238→        heat_silks: heat.silks.clone(),
   239→        paddock_file: heat.paddock_file.clone(),
   240→        paddock_content,
   241→        pace_coronet: None,
   242→        pace_silks: None,
   243→        pace_state: None,
   244→        spec: None,
   245→        direction: None,
   246→        recent_work,
   247→    };
   248→
   249→    for coronet_key in &heat.order {
   250→        if let Some(pace) = heat.paces.get(coronet_key) {
   251→            if let Some(tack) = pace.tacks.first() {
   252→                match tack.state {
   253→                    PaceState::Rough | PaceState::Bridled => {
   254→                        output.pace_coronet = Some(coronet_key.clone());
   255→                        output.pace_silks = Some(tack.silks.clone());
   256→                        output.pace_state = Some(match tack.state {
   257→                            PaceState::Rough => "rough".to_string(),
   258→                            PaceState::Bridled => "bridled".to_string(),
   259→                            _ => unreachable!(),
   260→                        });
   261→                        output.spec = Some(tack.text.clone());
   262→                        if tack.state == PaceState::Bridled {
   263→                            output.direction = tack.direction.clone();
   264→                        }
   265→                        break;
   266→                    }
   267→                    _ => continue,
   268→                }
   269→            }
   270→        }
   271→    }
   272→
   273→    // Output JSON
   274→    match serde_json::to_string_pretty(&output) {
   275→        Ok(json) => {
   276→            println!("{}", json);
   277→            0
   278→        }
   279→        Err(e) => {
   280→            eprintln!("jjx_saddle: error serializing output: {}", e);
   281→            1
   282→        }
   283→    }
   284→}
