   286→// ============================================================================
   287→// Parade - Display comprehensive Heat status for project review
   288→// ============================================================================
   289→
   290→/// Arguments for parade command
   291→#[derive(Debug)]
   292→pub struct jjrq_ParadeArgs {
   293→    pub file: std::path::PathBuf,
   294→    pub target: String,
   295→    pub full: bool,
   296→    pub remaining: bool,
   297→}
   298→
   299→/// Run the parade command - display comprehensive Heat status
   300→pub fn jjrq_run_parade(args: jjrq_ParadeArgs) -> i32 {
   301→    let gallops = match Gallops::jjrg_load(&args.file) {
   302→        Ok(g) => g,
   303→        Err(e) => {
   304→            eprintln!("jjx_parade: error: {}", e);
   305→            return 1;
   306→        }
   307→    };
   308→
   309→    // Determine target type by length
   310→    let target_str = args.target.strip_prefix('₢').or_else(|| args.target.strip_prefix('₣')).unwrap_or(&args.target);
   311→
   312→    if target_str.len() == 5 {
   313→        // Coronet - pace view
   314→        let coronet = match Coronet::jjrf_parse(&args.target) {
   315→            Ok(c) => c,
   316→            Err(e) => {
   317→                eprintln!("jjx_parade: error: {}", e);
   318→                return 1;
   319→            }
   320→        };
   321→
   322→        // Extract parent firemark
   323→        let firemark = coronet.jjrf_parent_firemark();
   324→        let heat_key = firemark.jjrf_display();
   325→        let heat = match gallops.heats.get(&heat_key) {
   326→            Some(h) => h,
   327→            None => {
   328→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   329→                return 1;
   330→            }
   331→        };
   332→
   333→        // Find pace
   334→        let coronet_key = coronet.jjrf_display();
   335→        let pace = match heat.paces.get(&coronet_key) {
   336→            Some(p) => p,
   337→            None => {
   338→                eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
   339→                return 1;
   340→            }
   341→        };
   342→
   343→        // Display tack history - iterate in reverse order (oldest first)
   344→        if !pace.tacks.is_empty() {
   345→            // Print header with current state from tacks[0]
   346→            let current_tack = &pace.tacks[0];
   347→            println!("Pace: {} ({})", current_tack.silks, coronet_key);
   348→            println!("Heat: {}", heat_key);
   349→            println!();
   350→
   351→            // Iterate tacks in reverse order (oldest first)
   352→            for (index, tack) in pace.tacks.iter().rev().enumerate() {
   353→                let state_str = zjjrq_pace_state_str(&tack.state);
   354→                let commit_str = if tack.commit == "0000000" {
   355→                    "(no commit)".to_string()
   356→                } else {
   357→                    tack.commit.clone()
   358→                };
   359→
   360→                println!("[{}] {} ({})", index, state_str, commit_str);
   361→                println!("    Silks: {}", tack.silks);
   362→                if let Some(ref direction) = tack.direction {
   363→                    println!("    Direction: {}", direction);
   364→                }
   365→                println!();
   366→                // Indent spec text
   367→                for line in tack.text.lines() {
   368→                    println!("    {}", line);
   369→                }
   370→                println!();
   371→            }
   372→        }
   373→    } else if target_str.len() == 2 {
   374→        // Firemark - heat view
   375→        let firemark = match Firemark::jjrf_parse(&args.target) {
   376→            Ok(fm) => fm,
   377→            Err(e) => {
   378→                eprintln!("jjx_parade: error: {}", e);
   379→                return 1;
   380→            }
   381→        };
   382→
   383→        let heat_key = firemark.jjrf_display();
   384→        let heat = match gallops.heats.get(&heat_key) {
   385→            Some(h) => h,
   386→            None => {
   387→                eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   388→                return 1;
   389→            }
   390→        };
   391→
   392→        if args.full {
   393→            // Full view: paddock + all specs
   394→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   395→                Ok(content) => content,
   396→                Err(e) => {
   397→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   398→                    return 1;
   399→                }
   400→            };
